(window.webpackJsonp=window.webpackJsonp||[]).push([[416],{685:function(s){s.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{string}</span> <span class=\\"hljs-variable\\">word</span></span>\\n * <span class=\\"hljs-doctag\\">@return <span class=\\"hljs-type\\">{number}</span></span>\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> minimumDistance = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">word</span>) </span>{\\n  <span class=\\"hljs-keyword\\">let</span> letter2p={}\\n  <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">0</span>;i&lt;<span class=\\"hljs-number\\">26</span>;i++){\\n    <span class=\\"hljs-keyword\\">let</span> x=<span class=\\"hljs-built_in\\">Math</span>.floor(i/<span class=\\"hljs-number\\">6</span>)\\n    <span class=\\"hljs-keyword\\">let</span> y=i % <span class=\\"hljs-number\\">6</span>\\n    letter2p[<span class=\\"hljs-built_in\\">String</span>.fromCharCode(i+<span class=\\"hljs-number\\">65</span>)]=[x,y]\\n  }\\n  <span class=\\"hljs-keyword\\">let</span> res=<span class=\\"hljs-literal\\">Infinity</span>\\n  <span class=\\"hljs-keyword\\">let</span> lf=<span class=\\"hljs-number\\">0</span>\\n  <span class=\\"hljs-keyword\\">let</span> rf=<span class=\\"hljs-number\\">1</span>\\n  <span class=\\"hljs-keyword\\">let</span> hash={}\\n\\n  <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span> <span class=\\"hljs-title\\">resolve</span>(<span class=\\"hljs-params\\">left,right</span>)</span>{\\n    <span class=\\"hljs-keyword\\">if</span>(right&gt;=word.length)<span class=\\"hljs-keyword\\">return</span> <span class=\\"hljs-number\\">0</span>\\n    <span class=\\"hljs-keyword\\">if</span>(hash[left+<span class=\\"hljs-string\\">\' \'</span>+right])<span class=\\"hljs-keyword\\">return</span> hash[left+<span class=\\"hljs-string\\">\' \'</span>+right]\\n\\n    <span class=\\"hljs-comment\\">// for(let j=right+1;j&lt;word.length;j++){</span>\\n    <span class=\\"hljs-keyword\\">let</span> minDis=<span class=\\"hljs-built_in\\">Math</span>.min(resolve(left,right+<span class=\\"hljs-number\\">1</span>)+getDis(right,right+<span class=\\"hljs-number\\">1</span>),resolve(right,right+<span class=\\"hljs-number\\">1</span>)+getDis(left,right+<span class=\\"hljs-number\\">1</span>))\\n    <span class=\\"hljs-comment\\">// }</span>\\n    <span class=\\"hljs-comment\\">// console.log(minDis,left,right,getDis(right,right+1))</span>\\n    hash[left+<span class=\\"hljs-string\\">\' \'</span>+right]=minDis\\n    <span class=\\"hljs-keyword\\">return</span> minDis\\n  }\\n  \\n  \\n  <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=rf;i&lt;word.length;i++){\\n    <span class=\\"hljs-keyword\\">let</span> distance=getDisBetweenLeftRight(lf,i)\\n    res=<span class=\\"hljs-built_in\\">Math</span>.min(resolve(i<span class=\\"hljs-number\\">-1</span>,i)+distance,res)\\n    <span class=\\"hljs-comment\\">// console.log(lf,i,res,distance)</span>\\n  }\\n  <span class=\\"hljs-keyword\\">return</span> res\\n  \\n  <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span> <span class=\\"hljs-title\\">getDisBetweenLeftRight</span>(<span class=\\"hljs-params\\">lf,rf</span>)</span>{\\n    <span class=\\"hljs-keyword\\">let</span> last=lf\\n    <span class=\\"hljs-keyword\\">let</span> dis=<span class=\\"hljs-number\\">0</span>\\n    <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> j=lf+<span class=\\"hljs-number\\">1</span>;j&lt;rf;j++){\\n      dis+=getDis(last,j)\\n      last=j\\n    }\\n    <span class=\\"hljs-keyword\\">return</span> dis\\n  }\\n  <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span> <span class=\\"hljs-title\\">getDis</span>(<span class=\\"hljs-params\\">i1,i2</span>)</span>{\\n    <span class=\\"hljs-keyword\\">if</span>(i2&gt;=word.length)<span class=\\"hljs-keyword\\">return</span> <span class=\\"hljs-number\\">0</span>\\n    <span class=\\"hljs-keyword\\">let</span> l1=word[i1]\\n    <span class=\\"hljs-keyword\\">let</span> l2=word[i2]\\n    <span class=\\"hljs-comment\\">// console.log(letter2p[l2],l2,i2)</span>\\n    <span class=\\"hljs-keyword\\">let</span> [x1,y1]=letter2p[l1]\\n    <span class=\\"hljs-keyword\\">let</span> [x2,y2]=letter2p[l2]\\n    <span class=\\"hljs-keyword\\">return</span> <span class=\\"hljs-built_in\\">Math</span>.abs(x1-x2)+<span class=\\"hljs-built_in\\">Math</span>.abs(y1-y2)\\n  }\\n};\\n</code></pre>\\n"],"titleSlug":"minimum-distance-to-type-a-word-using-two-fingers","hasThinking":false,"content":"<p><img alt=\\"\\" src=\\"https://assets.leetcode-cn.com/aliyun-lc-upload/uploads/2020/01/11/leetcode_keyboard.png\\" style=\\"height: 250px; width: 417px;\\"></p>\\n\\n<p>\u4e8c\u6307\u8f93\u5165\u6cd5\u5b9a\u5236\u952e\u76d8\u5728 XY \u5e73\u9762\u4e0a\u7684\u5e03\u5c40\u5982\u4e0a\u56fe\u6240\u793a\uff0c\u5176\u4e2d\u6bcf\u4e2a\u5927\u5199\u82f1\u6587\u5b57\u6bcd\u90fd\u4f4d\u4e8e\u67d0\u4e2a\u5750\u6807\u5904\uff0c\u4f8b\u5982\u5b57\u6bcd&nbsp;<strong>A</strong>&nbsp;\u4f4d\u4e8e\u5750\u6807&nbsp;<strong>(0,0)</strong>\uff0c\u5b57\u6bcd&nbsp;<strong>B</strong>&nbsp;\u4f4d\u4e8e\u5750\u6807&nbsp;<strong>(0,1)</strong>\uff0c\u5b57\u6bcd&nbsp;<strong>P</strong>&nbsp;\u4f4d\u4e8e\u5750\u6807&nbsp;<strong>(2,3)</strong>&nbsp;\u4e14\u5b57\u6bcd <strong>Z</strong>&nbsp;\u4f4d\u4e8e\u5750\u6807&nbsp;<strong>(4,1)</strong>\u3002</p>\\n\\n<p>\u7ed9\u4f60\u4e00\u4e2a\u5f85\u8f93\u5165\u5b57\u7b26\u4e32&nbsp;<code>word</code>\uff0c\u8bf7\u4f60\u8ba1\u7b97\u5e76\u8fd4\u56de\u5728\u4ec5\u4f7f\u7528\u4e24\u6839\u624b\u6307\u7684\u60c5\u51b5\u4e0b\uff0c\u952e\u5165\u8be5\u5b57\u7b26\u4e32\u9700\u8981\u7684\u6700\u5c0f\u79fb\u52a8\u603b\u8ddd\u79bb\u3002\u5750\u6807&nbsp;<strong>(x<sub>1</sub>,y<sub>1</sub>)</strong> \u548c <strong>(x<sub>2</sub>,y<sub>2</sub>)</strong> \u4e4b\u95f4\u7684\u8ddd\u79bb\u662f&nbsp;<strong>|x<sub>1</sub> - x<sub>2</sub>| + |y<sub>1</sub> - y<sub>2</sub>|</strong>\u3002&nbsp;</p>\\n\\n<p>\u6ce8\u610f\uff0c\u4e24\u6839\u624b\u6307\u7684\u8d77\u59cb\u4f4d\u7f6e\u662f\u96f6\u4ee3\u4ef7\u7684\uff0c\u4e0d\u8ba1\u5165\u79fb\u52a8\u603b\u8ddd\u79bb\u3002\u4f60\u7684\u4e24\u6839\u624b\u6307\u7684\u8d77\u59cb\u4f4d\u7f6e\u4e5f\u4e0d\u5fc5\u4ece\u9996\u5b57\u6bcd\u6216\u8005\u524d\u4e24\u4e2a\u5b57\u6bcd\u5f00\u59cb\u3002</p>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u793a\u4f8b 1\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>word = &quot;CAKE&quot;\\n<strong>\u8f93\u51fa\uff1a</strong>3\\n<strong>\u89e3\u91ca\uff1a \\n</strong>\u4f7f\u7528\u4e24\u6839\u624b\u6307\u8f93\u5165 &quot;CAKE&quot; \u7684\u6700\u4f73\u65b9\u6848\u4e4b\u4e00\u662f\uff1a \\n\u624b\u6307 1 \u5728\u5b57\u6bcd &#39;C&#39; \u4e0a -&gt; \u79fb\u52a8\u8ddd\u79bb = 0 \\n\u624b\u6307 1 \u5728\u5b57\u6bcd &#39;A&#39; \u4e0a -&gt; \u79fb\u52a8\u8ddd\u79bb = \u4ece\u5b57\u6bcd &#39;C&#39; \u5230\u5b57\u6bcd &#39;A&#39; \u7684\u8ddd\u79bb = 2 \\n\u624b\u6307 2 \u5728\u5b57\u6bcd &#39;K&#39; \u4e0a -&gt; \u79fb\u52a8\u8ddd\u79bb = 0 \\n\u624b\u6307 2 \u5728\u5b57\u6bcd &#39;E&#39; \u4e0a -&gt; \u79fb\u52a8\u8ddd\u79bb = \u4ece\u5b57\u6bcd &#39;K&#39; \u5230\u5b57\u6bcd &#39;E&#39; \u7684\u8ddd\u79bb  = 1 \\n\u603b\u8ddd\u79bb = 3\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 2\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>word = &quot;HAPPY&quot;\\n<strong>\u8f93\u51fa\uff1a</strong>6\\n<strong>\u89e3\u91ca\uff1a </strong>\\n\u4f7f\u7528\u4e24\u6839\u624b\u6307\u8f93\u5165 &quot;HAPPY&quot; \u7684\u6700\u4f73\u65b9\u6848\u4e4b\u4e00\u662f\uff1a\\n\u624b\u6307 1 \u5728\u5b57\u6bcd &#39;H&#39; \u4e0a -&gt; \u79fb\u52a8\u8ddd\u79bb = 0\\n\u624b\u6307 1 \u5728\u5b57\u6bcd &#39;A&#39; \u4e0a -&gt; \u79fb\u52a8\u8ddd\u79bb = \u4ece\u5b57\u6bcd &#39;H&#39; \u5230\u5b57\u6bcd &#39;A&#39; \u7684\u8ddd\u79bb = 2\\n\u624b\u6307 2 \u5728\u5b57\u6bcd &#39;P&#39; \u4e0a -&gt; \u79fb\u52a8\u8ddd\u79bb = 0\\n\u624b\u6307 2 \u5728\u5b57\u6bcd &#39;P&#39; \u4e0a -&gt; \u79fb\u52a8\u8ddd\u79bb = \u4ece\u5b57\u6bcd &#39;P&#39; \u5230\u5b57\u6bcd &#39;P&#39; \u7684\u8ddd\u79bb = 0\\n\u624b\u6307 1 \u5728\u5b57\u6bcd &#39;Y&#39; \u4e0a -&gt; \u79fb\u52a8\u8ddd\u79bb = \u4ece\u5b57\u6bcd &#39;A&#39; \u5230\u5b57\u6bcd &#39;Y&#39; \u7684\u8ddd\u79bb = 4\\n\u603b\u8ddd\u79bb = 6\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 3\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>word = &quot;NEW&quot;\\n<strong>\u8f93\u51fa\uff1a</strong>3\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 4\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>word = &quot;YEAR&quot;\\n<strong>\u8f93\u51fa\uff1a</strong>7\\n</pre>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li><code>2 &lt;= word.length &lt;= 300</code></li>\\n\\t<li>\u6bcf\u4e2a <code>word[i]</code>&nbsp;\u90fd\u662f\u4e00\u4e2a\u5927\u5199\u82f1\u6587\u5b57\u6bcd\u3002</li>\\n</ul>\\n","title":"1320. \u4e8c\u6307\u8f93\u5165\u7684\u7684\u6700\u5c0f\u8ddd\u79bb","relatedTags":["\u52a8\u6001\u89c4\u5212"],"difficult":"Hard","lang":["javascript"],"uniqueID":"1320"}')}}]);